import{_ as t,o as i,c as s,i as a}from"./chunks/framework.DP1yFSuu.js";const m=JSON.parse('{"title":"Design Contribution Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/design-contribution.md","filePath":"contributing/design-contribution.md"}'),o={name:"contributing/design-contribution.md"};function n(l,e,r,d,c,h){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="design-contribution-guidelines" tabindex="-1">Design Contribution Guidelines <a class="header-anchor" href="#design-contribution-guidelines" aria-label="Permalink to &quot;Design Contribution Guidelines&quot;">​</a></h1><p>Designers play a critical role in the Cobalt Design System. This guide covers how to work with the Figma library, propose design changes, and collaborate with development during implementation.</p><h2 id="figma-library-structure" tabindex="-1">Figma Library Structure <a class="header-anchor" href="#figma-library-structure" aria-label="Permalink to &quot;Figma Library Structure&quot;">​</a></h2><p>The Cobalt Figma library is organized into the following files:</p><table tabindex="0"><thead><tr><th>File</th><th>Contents</th><th>Access</th></tr></thead><tbody><tr><td><strong>Cobalt Foundations</strong></td><td>Color palettes, typography scales, spacing, elevation, icons</td><td>View (all), Edit (design system team)</td></tr><tr><td><strong>Cobalt Components</strong></td><td>All production component specs with variants and states</td><td>View (all), Edit (design system team)</td></tr><tr><td><strong>Cobalt Patterns</strong></td><td>Composed patterns and page-level templates</td><td>View (all), Edit (design system team)</td></tr><tr><td><strong>Cobalt Playground</strong></td><td>Sandbox for prototyping and experimentation</td><td>Edit (all designers)</td></tr></tbody></table><p>Each component page in the library includes:</p><ul><li><strong>Anatomy diagram</strong> — labeled parts and slots</li><li><strong>Variant matrix</strong> — all property and state combinations</li><li><strong>Spacing and sizing specs</strong> — using Cobalt token values</li><li><strong>Interaction notes</strong> — hover, focus, active, and disabled states</li><li><strong>Accessibility annotations</strong> — roles, labels, keyboard behavior</li></ul><blockquote><p><strong>Tip:</strong> Always branch from the latest published version of the library. Working from an outdated branch leads to merge conflicts and inconsistent specs.</p></blockquote><h2 id="how-to-propose-design-changes" tabindex="-1">How to Propose Design Changes <a class="header-anchor" href="#how-to-propose-design-changes" aria-label="Permalink to &quot;How to Propose Design Changes&quot;">​</a></h2><h3 id="minor-changes" tabindex="-1">Minor Changes <a class="header-anchor" href="#minor-changes" aria-label="Permalink to &quot;Minor Changes&quot;">​</a></h3><p>For small adjustments (e.g., spacing tweaks, color refinements, icon updates):</p><ol><li>Create a <strong>branch</strong> in the relevant Figma file</li><li>Make your changes, annotating what was modified and why</li><li>Open a GitHub Discussion or Issue with a link to the branch and a brief description</li><li>A design system designer will review and merge within 3 business days</li></ol><h3 id="major-changes" tabindex="-1">Major Changes <a class="header-anchor" href="#major-changes" aria-label="Permalink to &quot;Major Changes&quot;">​</a></h3><p>For significant updates (e.g., new variants, interaction pattern changes, component redesigns):</p><ol><li>Open a <strong>GitHub Discussion</strong> in the Design Proposals category</li><li>Include the problem statement, proposed solution, and supporting research</li><li>Create a Figma branch with the proposed design and link it in the discussion</li><li>Present the proposal at the next Design System Review meeting (biweekly, Tuesdays)</li><li>Iterate based on feedback until the proposal reaches consensus</li></ol><h3 id="new-components" tabindex="-1">New Components <a class="header-anchor" href="#new-components" aria-label="Permalink to &quot;New Components&quot;">​</a></h3><p>New component designs follow the <a href="./component-proposal.html">Component Proposal Process</a>. The design deliverables required are:</p><ul><li>Complete variant and state matrix</li><li>Light and dark theme versions</li><li>Responsive behavior documentation</li><li>Accessibility annotations</li><li>Redline specs with token references</li></ul><h2 id="design-review-checklist" tabindex="-1">Design Review Checklist <a class="header-anchor" href="#design-review-checklist" aria-label="Permalink to &quot;Design Review Checklist&quot;">​</a></h2><p>Before a design is approved for development, it must pass the following review:</p><h3 id="visual-consistency" tabindex="-1">Visual Consistency <a class="header-anchor" href="#visual-consistency" aria-label="Permalink to &quot;Visual Consistency&quot;">​</a></h3><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Uses only Cobalt design tokens — no hard-coded values</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Follows the established grid and spacing system</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Typography uses defined type scale styles</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Colors pass WCAG 2.2 AA contrast requirements (4.5:1 for text, 3:1 for UI elements)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Works in both light and dark themes</li></ul><h3 id="interaction-design" tabindex="-1">Interaction Design <a class="header-anchor" href="#interaction-design" aria-label="Permalink to &quot;Interaction Design&quot;">​</a></h3><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> All interactive states are documented (default, hover, focus, active, disabled)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Focus indicators are visible and consistent with the system</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Transitions and animations follow Cobalt motion guidelines</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Touch targets meet minimum 44x44px requirement</li></ul><h3 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h3><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> ARIA roles and labels are specified in annotations</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Keyboard interaction pattern is documented</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Screen reader behavior is described</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> High contrast mode is considered</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Reduced motion alternatives are provided for animations</li></ul><h3 id="documentation-readiness" tabindex="-1">Documentation Readiness <a class="header-anchor" href="#documentation-readiness" aria-label="Permalink to &quot;Documentation Readiness&quot;">​</a></h3><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Component anatomy is labeled</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Usage guidelines describe when to use (and when not to use) the component</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Edge cases are documented (long text, empty states, error states)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Content guidelines are provided for any text-bearing elements</li></ul><h2 id="handoff-to-development" tabindex="-1">Handoff to Development <a class="header-anchor" href="#handoff-to-development" aria-label="Permalink to &quot;Handoff to Development&quot;">​</a></h2><p>Once a design is approved, the handoff process ensures a smooth transition to implementation:</p><ol><li><strong>Publish the Figma branch</strong> — Merge the approved design into the main library file</li><li><strong>Create a development issue</strong> — Use the Component Implementation template, linking to the Figma spec</li><li><strong>Token mapping</strong> — Provide a table mapping design values to CSS custom properties (<code>--co-</code> tokens)</li><li><strong>Pair with a developer</strong> — Schedule a 30-minute walkthrough of the spec with the assigned developer</li><li><strong>Review implementation</strong> — Compare the built component against the Figma spec at each milestone</li></ol><h3 id="token-mapping-example" tabindex="-1">Token Mapping Example <a class="header-anchor" href="#token-mapping-example" aria-label="Permalink to &quot;Token Mapping Example&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Design Property</th><th>Figma Token</th><th>CSS Custom Property</th></tr></thead><tbody><tr><td>Background (primary)</td><td><code>brand/500</code></td><td><code>--co-button-background-primary</code></td></tr><tr><td>Background (hover)</td><td><code>brand/600</code></td><td><code>--co-button-background-primary-hover</code></td></tr><tr><td>Text color</td><td><code>neutral/white</code></td><td><code>--co-button-color-primary</code></td></tr><tr><td>Border radius</td><td><code>radius/md</code></td><td><code>--co-button-border-radius</code></td></tr><tr><td>Padding horizontal</td><td><code>spacing/4</code></td><td><code>--co-button-padding-inline</code></td></tr></tbody></table><blockquote><p><strong>Note:</strong> Developers should never need to inspect pixel values from Figma. Every value should map to a named token. If a design requires a value that doesn&#39;t exist as a token, that&#39;s a signal to propose a new token first.</p></blockquote>',34)])])}const b=t(o,[["render",n]]);export{m as __pageData,b as default};
